sys_script_client.script:
function onSubmit() {

    // Only run when state is Classification
    if (g_form.getValue('cr_state') != '2')
        return true;

    var product = g_form.getValue('product');
    var category = g_form.getValue('cr_category');
    var commercial = g_form.getValue('commercial_classification');
    var group = g_form.getValue('assignment_group');

    // Debugging
    console.log('Product = ' + product);
    console.log('Category = ' + category);
    console.log('Commercial = ' + commercial);
    console.log('Group = ' + group);

    // All mandatory fields completed
    if (product && category && commercial && group) {

        g_form.setValue('cr_state', '3');

        g_form.addInfoMessage(
            'State automatically moved to Impact Assessment.'
        );
    }

    return true;
}
